addToBasket:
export const addToBasket = pikkuSessionlessFunc({
  expose: true,
  description:
    'Add an item to a basket, or increase its quantity if already present.',
  input: AddToBasketInput,
  func: async ({ kysely }, { basketId, itemId, quantity }) => {
    const item = await kysely
      .selectFrom('item')
      .select(['stock', 'isActive'])
      .where('itemId', '=', itemId)
      .executeTakeFirst();

    if (!item || !item.isActive)
      throw new Error('Item not available');

    const existing = await kysely
      .selectFrom('basketItem')
      .select(['basketItemId', 'quantity'])
      .where('basketId', '=', basketId)
      .where('itemId', '=', itemId)
      .executeTakeFirst();

    if (existing) {
      const newQty = existing.quantity + quantity;
      if (newQty > item.stock) throw new Error('Not enough stock');
      await kysely
        .updateTable('basketItem')
        .set({ quantity: newQty })
        .where('basketItemId', '=', existing.basketItemId)
        .execute();
    } else {
      if (quantity > item.stock)
        throw new Error('Not enough stock');
      await kysely
        .insertInto('basketItem')
        .values({
          basketItemId: randomUUID(),
          basketId,
          itemId,
          quantity,
        })
        .execute();
    }

    await kysely
      .updateTable('basket')
      .set({ updatedAt: new Date().toISOString() })
      .where('basketId', '=', basketId)
      .execute();
  },
});

getBasket:
export const getBasket = pikkuSessionlessFunc({
  expose: true,
  description:
    'Get basket for the current user or session. Creates one if it does not exist.',
  input: GetBasketInput,
  output: GetBasketOutput,
  func: async ({ kysely, userSession }, { sessionId }) => {
    const userId = userSession?.userId ?? null;
    const sid = sessionId ?? null;

    // Find or create basket
    let basket = userId
      ? await kysely
          .selectFrom('basket')
          .selectAll()
          .where('userId', '=', userId)
          .executeTakeFirst()
      : sid
        ? await kysely
            .selectFrom('basket')
            .selectAll()
            .where('sessionId', '=', sid)
            .executeTakeFirst()
        : null;

    if (!basket) {
      const basketId = randomUUID();
      const now = new Date().toISOString();
      await kysely
        .insertInto('basket')
        .values({
          basketId,
          userId,
          sessionId: sid,
          createdAt: now,
          updatedAt: now,
        })
        .execute();
      return { basketId, items: [], totalCents: 0, itemCount: 0 };
    }

    const rows = await kysely
      .selectFrom('basketItem')
      .innerJoin('item', 'item.itemId', 'basketItem.itemId')
      .select([
        'basketItem.basketItemId',
        'basketItem.itemId',
        'basketItem.quantity',
        'item.name',
        'item.slug',
        'item.priceCents',
        'item.imageUrl',
      ])
      .where('basketItem.basketId', '=', basket.basketId)
      .execute();

    const items = rows.map((r) => ({
      basketItemId: r.basketItemId,
      itemId: r.itemId,
      name: r.name,
      slug: r.slug,
      priceCents: r.priceCents,
      imageUrl: r.imageUrl,
      quantity: r.quantity,
      lineTotalCents: r.priceCents * r.quantity,
    }));

    return {
      basketId: basket.basketId,
      items,
      totalCents: items.reduce(
        (sum, i) => sum + i.lineTotalCents,
        0,
      ),
      itemCount: items.reduce((sum, i) => sum + i.quantity, 0),
    };
  },
});

