listItems:
export const listItems = pikkuSessionlessFunc({
  expose: true,
  description:
    'List items, optionally filtered by category or search query.',
  input: ListItemsInput,
  output: ListItemsOutput,
  func: async (
    { kysely },
    { categorySlug, search, limit, offset },
  ) => {
    let query = kysely
      .selectFrom('item')
      .innerJoin(
        'category',
        'category.categoryId',
        'item.categoryId',
      )
      .select([
        'item.itemId',
        'item.name',
        'item.slug',
        'item.description',
        'item.priceCents',
        'item.stock',
        'item.imageUrl',
        'category.categoryId',
        'category.name as categoryName',
        'category.slug as categorySlug',
      ])
      .where('item.isActive', '=', 1);

    if (categorySlug) {
      query = query.where('category.slug', '=', categorySlug);
    }
    if (search) {
      query = query.where((eb) =>
        eb.or([
          eb('item.name', 'like', `%${search}%`),
          eb('item.description', 'like', `%${search}%`),
        ]),
      );
    }

    const [rows, countRow] = await Promise.all([
      query.limit(limit).offset(offset).execute(),
      query
        .select((eb) => eb.fn.countAll<number>().as('count'))
        .executeTakeFirst(),
    ]);

    return {
      items: rows.map((r) => ({
        itemId: r.itemId,
        name: r.name,
        slug: r.slug,
        description: r.description,
        priceCents: r.priceCents,
        stock: r.stock,
        imageUrl: r.imageUrl,
        category: {
          categoryId: r.categoryId,
          name: r.categoryName,
          slug: r.categorySlug,
        },
      })),
      total: Number(countRow?.count ?? 0),
    };
  },
});

