export const updateItem = pikkuFunc({
  expose: true,
  description: 'Update an item. Admin only.',
  input: UpdateItemInput,
  func: async ({ kysely }, { itemId, ...patch }) => {
    const updates: Record<string, unknown> = {
      updatedAt: new Date().toISOString(),
    };
    if (patch.name !== undefined) updates.name = patch.name;
    if (patch.description !== undefined)
      updates.description = patch.description;
    if (patch.priceCents !== undefined)
      updates.priceCents = patch.priceCents;
    if (patch.stock !== undefined) updates.stock = patch.stock;
    if (patch.imageUrl !== undefined)
      updates.imageUrl = patch.imageUrl;
    if (patch.isActive !== undefined)
      updates.isActive = patch.isActive ? 1 : 0;

    await kysely
      .updateTable('item')
      .set(updates)
      .where('itemId', '=', itemId)
      .execute();
  },
});

