dailySalesReport:
export const dailySalesReport = pikkuVoidFunc({
  expose: false,
  description: 'Cron job: compute and log a daily sales summary.',
  func: async ({ kysely, logger }) => {
    const yesterday = new Date();
    yesterday.setDate(yesterday.getDate() - 1);
    yesterday.setHours(0, 0, 0, 0);
    const dayStart = yesterday.toISOString();

    const today = new Date(yesterday);
    today.setDate(today.getDate() + 1);
    const dayEnd = today.toISOString();

    const [summary, topItems] = await Promise.all([
      kysely
        .selectFrom('order')
        .select([
          (eb) => eb.fn.countAll<number>().as('orderCount'),
          (eb) =>
            eb.fn.sum<number>('totalCents').as('revenueCents'),
        ])
        .where('status', '=', 'paid')
        .where('createdAt', '>=', dayStart)
        .where('createdAt', '<', dayEnd)
        .executeTakeFirst(),
      kysely
        .selectFrom('orderItem')
        .innerJoin('order', 'order.orderId', 'orderItem.orderId')
        .innerJoin('item', 'item.itemId', 'orderItem.itemId')
        .select([
          'item.name',
          (eb) =>
            eb.fn.sum<number>('orderItem.quantity').as('unitsSold'),
        ])
        .where('order.status', '=', 'paid')
        .where('order.createdAt', '>=', dayStart)
        .where('order.createdAt', '<', dayEnd)
        .groupBy('orderItem.itemId')
        .orderBy('unitsSold', 'desc')
        .limit(5)
        .execute(),
    ]);

    logger.info({
      event: 'daily_sales_report',
      date: yesterday.toISOString().split('T')[0],
      orders: Number(summary?.orderCount ?? 0),
      revenueCents: Number(summary?.revenueCents ?? 0),
      topItems,
    });
  },
});

shopServices:
export const createSingletonServices = pikkuServices(
  async (config, existingServices) => {
    const variables =
      existingServices?.variables ??
      new TypedVariablesService(new LocalVariablesService());
    const secrets =
      existingServices?.secrets ??
      new TypedSecretService(new LocalSecretService(variables));
    const logger =
      existingServices?.logger ?? new JsonConsoleLogger();
    const schema =
      existingServices?.schema ?? new CFWorkerSchemaService(logger);
    const paymentService =
      existingServices?.paymentService ?? new FakePaymentService();

    // In CF Workers DATABASE_URL is injected by Fabric.
    // In local dev (pikku dev) existingServices.kysely is the node:sqlite instance.
    // In tests existingServices.kysely is provided by the test support layer.
    let kysely: Kysely<DB> | undefined;
    if (existingServices?.kysely) {
      kysely = existingServices.kysely as Kysely<DB>;
    } else {
      const databaseUrl = await variables.get('DATABASE_URL');
      if (databaseUrl) {
        if (/^postgres(ql)?:\/\//.test(databaseUrl)) {
          const [{ PostgresJSDialect }, postgres] =
            await Promise.all([
              import('kysely-postgres-js'),
              import('postgres'),
            ]);
          kysely = new Kysely<DB>({
            dialect: new PostgresJSDialect({
              postgres: postgres.default(databaseUrl),
            }),
            plugins: [new CamelCasePlugin()],
          });
        } else {
          kysely = new Kysely<DB>({
            dialect: new LibsqlWebDialect({ url: databaseUrl }),
            plugins: [new CamelCasePlugin()],
          });
        }
      } else {
        throw new Error(
          'kysely not provided: set DATABASE_URL or pass kysely via existingServices',
        );
      }
    }

    return {
      ...(existingServices ?? {}),
      config,
      variables,
      secrets,
      logger,
      schema,
      kysely,
      paymentService,
      audit: existingServices?.audit ?? new NoopAuditService(),
    };
  },
);

