const configFactory: AuthConfigOrFactory = async (services) => {
  const { kysely, secrets } = services as any;
  const secret =
    (await secrets.getSecret('AUTH_SECRET').catch(() => null)) ??
    DEV_AUTH_SECRET;

  return {
    providers: [
      Credentials({
        credentials: {
          email: { label: 'Email', type: 'email' },
          password: { label: 'Password', type: 'password' },
        },
        async authorize(credentials) {
          const email = (
            credentials?.email as string | undefined
          )?.toLowerCase();
          const password = credentials?.password as
            | string
            | undefined;
          if (!email || !password) return null;

          const user = await kysely
            .selectFrom('appUser')
            .where('email', '=', email)
            .select([
              'userId',
              'role',
              'name',
              'email',
              'passwordHash',
            ])
            .executeTakeFirst();

          if (!user || !user.passwordHash) return null;
          const ok = await verifyPassword(
            password,
            user.passwordHash,
          );
          if (!ok) return null;

          return {
            id: user.userId,
            email: user.email,
            name: user.name,
            role: user.role,
          };
        },
      }),
    ],
    callbacks: {
      jwt({ token, user }: any) {
        if (user) {
          token.role = user.role;
          token.userId = user.id;
        }
        return token;
      },
      session({ session, token }: any) {
        if (token) {
          session.role = token.role;
          session.userId = token.userId;
        }
        return session;
      },
    },
    session: { strategy: 'jwt' as const },
    secret,
    trustHost: true,
    basePath: '/auth',
  };
};

checkoutWorkflow:
export const checkoutWorkflow = pikkuWorkflowFunc<
  {
    basketId: string;
    userId: string;
    shippingAddress: ShippingAddress;
    cardToken?: string;
  },
  {
    orderId: string;
    status: 'paid' | 'payment_failed';
    totalCents: number;
  }
>({
  expose: true,
  func: async (
    { kysely, paymentService, queueService },
    data,
    { workflow },
  ) => {
    // Step 1: Validate basket — confirm items exist and stock is sufficient
    const { items, totalCents } = await workflow.do(
      'Validate basket',
      async () => {
        const rows = await kysely
          .selectFrom('basketItem')
          .innerJoin('item', 'item.itemId', 'basketItem.itemId')
          .select([
            'basketItem.itemId',
            'basketItem.quantity',
            'item.stock',
            'item.name',
            'item.priceCents',
          ])
          .where('basketItem.basketId', '=', data.basketId)
          .execute();
        if (rows.length === 0) throw new Error('Basket is empty');
        for (const i of rows) {
          if (i.quantity > i.stock)
            throw new Error(`Insufficient stock for "${i.name}"`);
        }
        return {
          items: rows,
          totalCents: rows.reduce(
            (s, i) => s + i.priceCents * i.quantity,
            0,
          ),
        };
      },
    );

    // Step 2: Persist order record and line items
    const orderId = randomUUID();
    await workflow.do('Create order', async () => {
      const now = new Date().toISOString();
      await kysely
        .insertInto('order')
        .values({
          orderId,
          userId: data.userId,
          status: 'pending',
          totalCents,
          shippingAddress: JSON.stringify(data.shippingAddress),
          createdAt: now,
          updatedAt: now,
        })
        .execute();
      await kysely
        .insertInto('orderItem')
        .values(
          items.map((i) => ({
            orderItemId: randomUUID(),
            orderId,
            itemId: i.itemId,
            quantity: i.quantity,
            unitPriceCents: i.priceCents,
          })),
        )
        .execute();
    });

    // Step 3: Charge the card — safely retried if the payment provider times out
    const payment = await workflow.do('Process payment', async () =>
      paymentService.charge({
        amountCents: totalCents,
        cardToken: data.cardToken,
        orderId,
      }),
    );

    // Step 4: Finalize order status and clear the basket on success
    const status =
      payment.status === 'succeeded'
        ? ('paid' as const)
        : ('payment_failed' as const);
    await workflow.do('Finalize', async () => {
      const now = new Date().toISOString();
      await kysely
        .updateTable('order')
        .set({ status, updatedAt: now })
        .where('orderId', '=', orderId)
        .execute();
      if (status === 'paid') {
        await kysely
          .deleteFrom('basketItem')
          .where('basketId', '=', data.basketId)
          .execute();
        await queueService?.add('send-order-confirmation', {
          orderId,
          userId: data.userId,
        });
      }
    });

    return { orderId, status, totalCents };
  },
});

