// A gateway handler receives a normalized GatewayInboundMessage regardless of platform.
export const handlePaymentWebhook = pikkuSessionlessFunc({
  expose: false,
  description:
    'Process payment webhook events from the payment provider.',
  func: async (
    { kysely, logger },
    { text, raw }: { text: string; raw: unknown },
  ) => {
    const payload = raw as {
      event: string;
      data: { orderId: string };
    };
    logger.info({ event: 'payment_webhook', type: payload.event });

    if (payload.event === 'payment.succeeded') {
      await kysely
        .updateTable('order')
        .set({
          status: 'paid',
          updatedAt: new Date().toISOString(),
        })
        .where('orderId', '=', payload.data.orderId)
        .execute();
    } else if (payload.event === 'payment.failed') {
      await kysely
        .updateTable('order')
        .set({
          status: 'payment_failed',
          updatedAt: new Date().toISOString(),
        })
        .where('orderId', '=', payload.data.orderId)
        .execute();
    }

    return { received: true };
  },
});

