    const item = await kysely
      .selectFrom('item')
      .select(['stock', 'name', 'isActive'])
      .where('itemId', '=', itemId)
      .executeTakeFirst();

    if (!item) throw new Error(`Item not found: ${itemId}`);
    return {
      available: item.stock > 0 && item.isActive === 1,
      stock: item.stock,
      name: item.name,
    };
  },
});

